/*\n# Create cost_price_history table\n\n1. Purpose\n- Records a snapshot of the cost price for each product line at the moment an\n  invoice or quotation is saved. This lets staff look back and see what the\n  cost price of a product was at the time of a sale, even if the product's\n  cost price changes later.\n\n2. New Tables\n- `cost_price_history`\n  - `id` (uuid, primary key)\n  - `product_id` (uuid, references products, nullable so history survives\n    even if a product is later deactivated)\n  - `product_name` (text) — denormalized name snapshot for display\n  - `product_sku` (text) — denormalized SKU snapshot for display\n  - `unit` (text) — unit used at the time of sale (e.g. "pcs", "box")\n  - `quantity` (numeric, default 0) — quantity added in this line\n  - `unit_price` (numeric, default 0) — sale price per unit at time of sale\n  - `cost_price_per_qty` (numeric, default 0) — cost price of 1 unit\n  - `cost_price_for_added_qty` (numeric, default 0) — cost price × quantity\n    for this single line item\n  - `total_cost_price_single` (numeric, default 0) — sum of cost_price_per_qty\n    across all lines in the parent invoice/quotation (per-unit cost total)\n  - `total_cost_price_added` (numeric, default 0) — sum of\n    cost_price_for_added_qty across all lines in the parent\n    invoice/quotation (total cost of goods sold)\n  - `recorded_at` (timestamptz, default now()) — time the record was created\n  - `invoice_id` (uuid, nullable, references invoices) — set when recorded\n    from an invoice\n  - `quotation_id` (uuid, nullable, references quotations) — set when\n    recorded from a quotation\n  - `created_at` (timestamptz, default now())\n\n3. Indexes\n- `idx_cost_price_history_product_id` on `product_id` for fast per-product\n  lookups.\n- `idx_cost_price_history_invoice_id` on `invoice_id` for fast per-invoice\n  lookups.\n- `idx_cost_price_history_quotation_id` on `quotation_id` for fast\n  per-quotation lookups.\n- `idx_cost_price_history_recorded_at` on `recorded_at` desc for\n  chronological sorting.\n\n4. Security\n- Enable RLS on `cost_price_history`.\n- Single-tenant app with no sign-in screen, so policies are scoped to\n  `TO anon, authenticated` with `USING (true)` / `WITH CHECK (true)` because\n  the data is intentionally shared across the whole tenant.\n- Four separate policies (select / insert / update / delete), never `FOR ALL`.\n- Policies are dropped before recreate so the migration is idempotent.\n\n5. Notes\n- Both `invoice_id` and `quotation_id` are nullable because a single history\n  row is written per line item and only one of the two parents is set.\n- `product_id` is nullable with `ON DELETE SET NULL` so historical records\n  are preserved even if a product is deleted.\n- `invoice_id` and `quotation_id` use `ON DELETE CASCADE` so history rows\n  are cleaned up when the parent document is removed.\n*/\n\nCREATE TABLE IF NOT EXISTS cost_price_history (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  product_id uuid REFERENCES products(id) ON DELETE SET NULL,\n  product_name text NOT NULL DEFAULT '',\n  product_sku text NOT NULL DEFAULT '',\n  unit text,\n  quantity numeric NOT NULL DEFAULT 0,\n  unit_price numeric NOT NULL DEFAULT 0,\n  cost_price_per_qty numeric NOT NULL DEFAULT 0,\n  cost_price_for_added_qty numeric NOT NULL DEFAULT 0,\n  total_cost_price_single numeric NOT NULL DEFAULT 0,\n  total_cost_price_added numeric NOT NULL DEFAULT 0,\n  recorded_at timestamptz NOT NULL DEFAULT now(),\n  invoice_id uuid REFERENCES invoices(id) ON DELETE CASCADE,\n  quotation_id uuid REFERENCES quotations(id) ON DELETE CASCADE,\n  created_at timestamptz NOT NULL DEFAULT now()\n);
\n\nALTER TABLE cost_price_history ENABLE ROW LEVEL SECURITY;
\n\nDROP POLICY IF EXISTS "anon_select_cost_price_history" ON cost_price_history;
\nCREATE POLICY "anon_select_cost_price_history" ON cost_price_history\n  FOR SELECT TO anon, authenticated USING (true);
\n\nDROP POLICY IF EXISTS "anon_insert_cost_price_history" ON cost_price_history;
\nCREATE POLICY "anon_insert_cost_price_history" ON cost_price_history\n  FOR INSERT TO anon, authenticated WITH CHECK (true);
\n\nDROP POLICY IF EXISTS "anon_update_cost_price_history" ON cost_price_history;
\nCREATE POLICY "anon_update_cost_price_history" ON cost_price_history\n  FOR UPDATE TO anon, authenticated USING (true) WITH CHECK (true);
\n\nDROP POLICY IF EXISTS "anon_delete_cost_price_history" ON cost_price_history;
\nCREATE POLICY "anon_delete_cost_price_history" ON cost_price_history\n  FOR DELETE TO anon, authenticated USING (true);
\n\nCREATE INDEX IF NOT EXISTS idx_cost_price_history_product_id\n  ON cost_price_history(product_id);
\nCREATE INDEX IF NOT EXISTS idx_cost_price_history_invoice_id\n  ON cost_price_history(invoice_id);
\nCREATE INDEX IF NOT EXISTS idx_cost_price_history_quotation_id\n  ON cost_price_history(quotation_id);
\nCREATE INDEX IF NOT EXISTS idx_cost_price_history_recorded_at\n  ON cost_price_history(recorded_at DESC);
\n;